SELECT name, temperature
FROM fluids
ORDER BY temperature DESC;

SELECT fluid_id, name, flow_rate
FROM fluids
WHERE flow_rate > (SELECT AVG(flow_rate) FROM fluids);

SELECT COUNT(fluid_id) AS num_fluids_above_average_temp
FROM fluids
WHERE temperature > (SELECT AVG(temperature) FROM fluids);

SELECT c1.block_class_name AS child_class, c2.block_class_name AS parent_class
FROM block_classes c1
LEFT JOIN block_classes c2 ON c1.parent_block_class_id = c2.block_class_id;

SELECT name, temperature, density 
FROM fluids 
ORDER BY temperature DESC;

SELECT *
FROM blocks
WHERE density > (SELECT AVG(density) FROM blocks);

SELECT fluid_id, block_id
FROM fluids
WHERE fluid_id = 5;

SELECT DISTINCT fluids.name AS fluid_name, blocks.name AS block_name
FROM fluids
JOIN blocks ON fluids.block_id = blocks.block_id;

SELECT COUNT(*) 
FROM fluids 
WHERE fluid_id > LAST_INSERT_ROWID() - 10;

SELECT localized_name
FROM fluids
WHERE fluid_id = 123;

SELECT AVG(cpu_usage) AS average_cpu_usage, AVG(memory_usage) AS average_memory_usage
   FROM server_logs
   WHERE tps > (
       SELECT AVG(tps)
       FROM server_logs
   );

SELECT 
    (SELECT name FROM fluids WHERE luminosity = (SELECT MAX(luminosity) FROM fluids)) AS fluid_with_highest_luminosity,
    (SELECT name FROM blocks WHERE luminosity = (SELECT MAX(luminosity) FROM blocks)) AS block_with_highest_luminosity;

SELECT f.name AS fluid_name, f.localized_name, b.name AS block_name
FROM fluids f
LEFT JOIN blocks b ON f.block_id = b.block_id;

SELECT name, temperature
FROM fluids
WHERE viscosity = (SELECT MAX(viscosity) FROM fluids);

SELECT name, localized_name
FROM fluids
WHERE fluid_id > 500;
